import fs from 'node:fs';
import path from 'node:path';
import { fileURLToPath } from 'node:url';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

const repoRoot = path.join(__dirname, '../../..');
const skillsDir = path.join(repoRoot, 'skills');
const generatedFile = path.join(__dirname, '../src/generated/skills.ts');

const skills = [];

function readFilesRecursively(dir, basePath = '') {
  const files = {};
  const entries = fs.readdirSync(dir, { withFileTypes: true });
  for (const entry of entries) {
    const fullPath = path.join(dir, entry.name);
    const relPath = basePath ? `${basePath}/${entry.name}` : entry.name;
    
    if (entry.isDirectory()) {
      Object.assign(files, readFilesRecursively(fullPath, relPath));
    } else if (entry.isFile() && entry.name.endsWith('.md')) {
      files[relPath] = fs.readFileSync(fullPath, 'utf8');
    }
  }
  return files;
}

const entries = fs.readdirSync(skillsDir, { withFileTypes: true });
for (const entry of entries) {
  if (entry.isDirectory()) {
    const slug = entry.name;
    const files = readFilesRecursively(path.join(skillsDir, slug));
    skills.push({ slug, files });
  }
}

const template = `// AUTO-GENERATED FILE - DO NOT EDIT
// This file is generated by scripts/bundle-skills.js
// Do not edit this file directly. Update the skills/ directory and run 'pnpm run build' or 'pnpm run bundle-skills'

export interface SkillAsset {
  slug: string;
  files: Record<string, string>;
}

export const SKILLS: SkillAsset[] = ${JSON.stringify(skills, null, 2)};
`;

fs.mkdirSync(path.dirname(generatedFile), { recursive: true });
fs.writeFileSync(generatedFile, template, 'utf8');
console.log(`[bundle-skills] Generated ${generatedFile} with ${skills.length} skills.`);
